changeSet.sql:
DO $$
DECLARE
    grants jsonb := '[
      {"role": "TENANT_ADMIN", "perms": ["uom:update","uom:delete"]},
      {"role": "MANAGER",      "perms": ["uom:update","uom:delete"]}
    ]'::jsonb;
    entry jsonb;
    rcode text;
    pcodes text[];
BEGIN
    FOR entry IN SELECT * FROM jsonb_array_elements(grants) LOOP
        rcode := entry->>'role';
        SELECT ARRAY(SELECT jsonb_array_elements_text(entry->'perms')) INTO pcodes;

        INSERT INTO role_permission (role_id, permission_id)
        SELECT r.id, p.id
        FROM roles r
        JOIN permissions p ON p.code = ANY(pcodes)
        WHERE r.code = rcode
        ON CONFLICT DO NOTHING;
    END LOOP;
END $$;
